/* Aula 09 — modelJs: Funções 1 */

function somar(a, b) {
  return a + b;
}

function ehMaiorDeIdade(idade) {
  return idade >= 18;
}

function formatarNome(nome) {
  const limpo = nome.trim().toLowerCase();
  if (limpo.length === 0) return '';
  return limpo[0].toUpperCase() + limpo.slice(1);
}

function calcularDesconto(preco, porcentagem) {
  const desconto = (preco * porcentagem) / 100;
  return preco - desconto;
}

const r1 = somar(10, 5);
console.log('somar:', r1);

const r2 = ehMaiorDeIdade(17);
console.log('maior de idade?', r2);

const r3 = formatarNome('  bRUNo  ');
console.log('formatarNome:', r3);

const r4 = calcularDesconto(100, 10);
console.log('calcularDesconto:', r4);
